import React, { useState } from "react";

const ProductSuggester = () => {
  const [selectedItems, setSelectedItems] = useState([]);
  const [suggestions, setSuggestions] = useState([]);

  const products = [
    { name: "Laptop", image: "/images/laptop.jpg", price: 20000000 },
    { name: "Mouse", image: "/images/mouse.jpg", price: 300000 },
    { name: "Keyboard", image: "/images/keyboard.jpg", price: 500000 },
    { name: "Headphones", image: "/images/headphone.jpg", price: 1500000 },
    { name: "Monitor", image: "/images/monitor.jpg", price: 4000000 },
  ];

  const toggleSelection = (productName) => {
    setSelectedItems((prev) =>
      prev.includes(productName)
        ? prev.filter((p) => p !== productName)
        : [...prev, productName]
    );
  };

  const getSuggestions = async () => {
    try {
      const response = await fetch("http://localhost:3000/api/suggest", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ selectedItems }),
      });

      if (!response.ok) throw new Error("Failed to get suggestions");

      const data = await response.json();
      setSuggestions(data);
    } catch (err) {
      console.error("Error fetching suggestions:", err);
    }
  };

  return (
    <div className="p-6 bg-gray-100 min-h-screen">
      <h1 className="text-3xl font-bold text-center mb-8 text-blue-700">
        Chọn sản phẩm để nhận gợi ý
      </h1>

      {/* Grid hiển thị sản phẩm */}
      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 flex gap-6">
        {products.map((product) => (
          <div
            key={product.name}
            className={`border rounded-xl p-4 shadow-md bg-white hover:shadow-lg transition relative ${
              selectedItems.includes(product.name) ? "ring-2 ring-blue-500" : ""
            }`}
          >
            <img
              src={product.image}
              alt={product.name}
              className="w-full h-40 object-cover rounded-md mb-3"
            />
            <h3 className="text-lg font-semibold mb-1">{product.name}</h3>
            <p className="text-green-600 font-bold mb-2">
              {product.price.toLocaleString()} ₫
            </p>

            <button
              onClick={() => toggleSelection(product.name)}
              className={`w-full py-2 rounded-lg text-white font-medium transition ${
                selectedItems.includes(product.name)
                  ? "bg-red-500 hover:bg-red-600"
                  : "bg-blue-600 hover:bg-blue-700"
              }`}
            >
              {selectedItems.includes(product.name) ? "Bỏ chọn" : "Chọn mua"}
            </button>
          </div>
        ))}
      </div>

      <div className="text-center mt-10">
        <button
          onClick={getSuggestions}
          className="bg-green-500 hover:bg-green-600 text-white px-8 py-3 rounded-full text-lg transition"
        >
          Gợi ý sản phẩm
        </button>
      </div>

      <h2 className="mt-10 text-2xl font-semibold text-center text-gray-800">
        Gợi ý mua thêm:
      </h2>
      <div className="mt-6">
        {suggestions.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {suggestions.map((sug, index) => (
              <div
                key={index}
                className="p-4 bg-white border rounded-lg shadow-md"
              >
                <h3 className="font-semibold text-lg">
                  {sug.items.join(", ")}{" "}
                  <span className="text-sm text-gray-500">
                    (Support: {(sug.support * 100).toFixed(2)}%)
                  </span>
                </h3>
              </div>
            ))}
          </div>
        ) : (
          <p className="text-center text-gray-500">Không có gợi ý.</p>
        )}
      </div>
    </div>
  );
};

export default ProductSuggester;
